  }, []);

  const handleNext = useCallback(() => {
    setAutoRotate(false);
    setActiveId((current) => {
      const idx = PLATFORMS.findIndex((p) => p.id === current);
      return PLATFORMS[(idx + 1) % PLATFORMS.length].id;
