              marginRight: -2,
              marginBottom: -1,
              fontSize: 11,
              lineHeight: "14px",
              letterSpacing: "-0.01em",
              whiteSpace: "nowrap",
              opacity: 0.95,
            }}
          >
            {meta}
          </span>
        )}
      </div>
      {tail && (
        <span
          aria-hidden="true"
          style={{
            position: "absolute",
            bottom: 0,
            [isMe ? "right" : "left"]: -7,
            width: 20,
            height: 18,
            background: tailColor,
            clipPath: `path('${isMe ? TAIL_ME : TAIL_THEM}')`,
          }}
        />
      )}
    </div>
  );
}

